text:
    # Add previous chat turns (this node only)
    if current_chat_history:
        for msg in current_chat_history:
            display_type = msg.get("display_type")
            tool_data = msg.get("tool_data")

            # Bring in uploaded file text as system context
            if display_type == "file_icon" and tool_data and tool_data.get("text"):
                if context_type == "pipeline":
                    continue
                formatted = format_file_data_for_context(
                    tool_data.get("filename"), tool_data.get("text")
                )
                if formatted:
                    messages.append({"role": "system", "content": formatted})
                continue

            if display_type == "1003_icon":
                formatted = format_1003_data_for_context(tool_data or msg.get("prompt"))
                if formatted:
                    messages.append({"role": "system", "content": formatted})
                continue

            # User prompt
            if msg.get("role") == "user" and msg.get("prompt"):
                messages.append({"role": "user", "content": msg["prompt"]})
            elif msg.get("prompt") and not msg.get("role"):
                messages.append({"role": "user", "content": msg["prompt"]})

            # Assistant (text and/or tool calls)
            if isinstance(msg, dict) and (msg.get("role") == "assistant" or msg.get("response") or msg.get("tool_calls")):
                assistant_message = {"role": "assistant"}
                has_content = False

                if msg.get("response") not in (None, ""):
                    assistant_message["content"] = msg["response"]
                    has_content = True
                else:
                    assistant_message["content"] = None

                if msg.get("tool_calls"):
                    if isinstance(msg["tool_calls"], list) and all(isinstance(tc, dict) for tc in msg["tool_calls"]):
                        assistant_message["tool_calls"] = msg["tool_calls"]
                        assistant_message["content"] = None
                        has_content = False
                    else:
                        logging.warning(f"Skipping invalid tool_calls format in history: {msg.get('tool_calls')}")

                if has_content or "tool_calls" in assistant_message:
                    messages.append(assistant_message)

                # Inline tool results after assistant tool_calls
                if msg.get("tool_calls") and msg.get("tool_results"):
                    if isinstance(msg.get("tool_results"), list):
                        for tool_result in msg.get("tool_results", []):
                            if isinstance(tool_result, dict) and tool_result.get("tool_call_id") and tool_result.get("response") is not None:
                                messages.append({
                                    "role": "tool",
                                    "tool_call_id": tool_result.get("tool_call_id"),
                                    "content": tool_result.get("response")
                                })
                            else:
                                logging.warning(f"Skipping invalid tool_result in history: {tool_result}")
                    else:
                        logging.warning(f"Skipping invalid tool_results format (expected list): {msg.get('tool_results')}")

            elif isinstance(msg, dict) and msg.get("role") == "tool":
                if msg.get("tool_call_id") and msg.get("content") is not None:
                    messages.append(msg)
                else:
                    logging.warning(f"Skipping invalid standalone tool message: {msg}")

            elif isinstance(msg, dict) and msg.get("role") not in ["user", "assistant", "tool", "system"]:
                logging.warning(f"Skipping message with unexpected role: {msg.get('role')}")
            elif not isinstance(msg, dict):
                logging.warning(f"Skipping non-dict item in chat history: {msg}")

    if user_prompt:
        messages.append({"role": "user", "content": user_prompt})

    return messages


# ===================== Node Handler =====================

def _handle_chat(chat_history, node_map, current_node, ndata,
                 user_id, chat_id, state, selected_model, temperature):
    """Opens chatbar; actual tool handling happens in /chat_message."""
    from workflow import run_subgraph_skip_choose_context
    logger = logging
    logger.info(f"[Node Handler] Processing Chat Node: {current_node}")

    prompt_text = ndata.get("text", "")
    show_prompt = ndata.get("show_prompt", True)

    if show_prompt and prompt_text.strip():
        yield _sse_event("user_prompt", {"message": prompt_text})

    existing_messages = chat_history.get(current_node, {}).get("messages", [])

    if current_node not in chat_history:
        chat_history[current_node] = {
            "type": "Chat",
            "messages": [],
            "model": selected_model,
            "temperature": temperature,
            "index": ndata.get("index", None)
        }
    else:
        chat_history[current_node]["messages"] = existing_messages
        chat_history[current_node]["model"] = selected_model
        chat_history[current_node]["temperature"] = temperature

    outs = ndata.get("output", [])
    nxt = outs[0].get("next_node") if outs else None
    chat_history[current_node]["next_node_after_chat"] = nxt

    save_chat_state(user_id, chat_id, node_map, chat_history, current_node, state.get("name"))
    logger.info(f"Saved initial state for Chat node {current_node}.")
